import{_ as n,o as e,c as a,a2 as t}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Sliding Window & Truncation Strategies","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/context-management/sliding-window.md","filePath":"research/concepts/context-management/sliding-window.md"}'),o={name:"research/concepts/context-management/sliding-window.md"};function l(p,s,r,i,c,d){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="sliding-window-truncation-strategies" tabindex="-1">Sliding Window &amp; Truncation Strategies <a class="header-anchor" href="#sliding-window-truncation-strategies" aria-label="Permalink to &quot;Sliding Window &amp; Truncation Strategies&quot;">​</a></h1><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>The simplest family of context compaction strategies operates on a single principle: drop or truncate content based on its position in the conversation or its age. These strategies require <strong>zero LLM calls</strong>, introduce <strong>near-zero latency</strong>, and are trivial to implement. Every production coding agent uses at least one of them.</p><p>The fundamental trade-off is stark: <strong>high information loss in exchange for simplicity and speed</strong>. A sliding window doesn&#39;t understand what it&#39;s discarding. It cannot distinguish a critical architectural decision from a routine <code>ls</code> output, relying solely on recency as a proxy for relevance.</p><p>Despite this, position-based strategies form the backbone of context management. They are the first line of defense against context overflow, and more sophisticated strategies (summarization, semantic compression) are layered on top rather than replacing them. This document surveys the major variants.</p><hr><h2 id="_2-simple-sliding-window" tabindex="-1">2. Simple Sliding Window <a class="header-anchor" href="#_2-simple-sliding-window" aria-label="Permalink to &quot;2. Simple Sliding Window&quot;">​</a></h2><p>The most basic approach: maintain a fixed-size window of recent messages and discard everything older.</p><p><strong>Mechanism:</strong></p><ul><li>Define a window size <code>W</code> (measured in messages or tokens).</li><li>When the conversation exceeds <code>W</code>, drop the oldest messages until it fits.</li><li>The window slides forward as new messages arrive.</li></ul><p><strong>Implementations:</strong> LangChain&#39;s <code>ConversationBufferWindowMemory</code> with configurable <code>k</code> (number of interaction pairs to retain). Most chat UIs that pass &quot;the last N messages&quot; to the API.</p><p><strong>Configuration choices:</strong></p><ul><li><strong>Message count</strong>: simple but imprecise — one message might be 10 tokens or 10,000.</li><li><strong>Token count</strong>: accurate budget control but requires a tokenizer pass.</li><li><strong>Turn count</strong>: each user-assistant pair counts as one turn. Good middle ground.</li></ul><p><strong>The critical problem:</strong> you lose ALL context about what happened before the window. The agent cannot recall original instructions, early decisions, or files it modified twenty turns ago — leading to repeated mistakes, contradicted decisions, and lost track of the original user request.</p><hr><h2 id="_3-anchor-preserving-window" tabindex="-1">3. Anchor-Preserving Window <a class="header-anchor" href="#_3-anchor-preserving-window" aria-label="Permalink to &quot;3. Anchor-Preserving Window&quot;">​</a></h2><p><strong>Key insight:</strong> the initial context — system prompt, first user message, setup instructions — should almost <strong>never</strong> be dropped. These messages define the entire task and agent behavior.</p><p>OpenHands implements this in <code>ConversationWindowCondenser</code>:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> ConversationWindowCondenser</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">RollingCondenser</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">    max_events</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 100</span></span>
<span class="line"><span style="color:#CDD6F4;">    keep_first</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 5</span><span style="color:#6C7086;font-style:italic;">   # Preserve initial setup/instructions</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> condense</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> events</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">events</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> &lt;=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">max_events</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#CDD6F4;"> events</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Keep first K events + last (max - K) events; forget the middle</span></span>
<span class="line"><span style="color:#CDD6F4;">        head </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> events</span><span style="color:#9399B2;">[:</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">keep_first</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">        tail </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> events</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">-</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">max_events </span><span style="color:#94E2D5;">-</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">keep_first</span><span style="color:#9399B2;">):]</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> head </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> tail</span></span></code></pre></div><p><strong>The &quot;first K + last N&quot; pattern:</strong> preserve bookends, drop the middle.</p><p><strong>Why the middle is safe(r) to drop:</strong> &quot;Lost in the middle&quot; research (Liu et al., 2023) showed LLMs pay most attention to context beginnings and endings. Information buried in the middle is already partially &quot;lost&quot; even when present. Dropping it removes content the model was least likely to leverage.</p><p>The <code>keep_first</code> parameter typically captures: system prompt (1 event), initial user request (1 event), and environment setup (2-3 events). This small anchor provides remarkable continuity — the agent retains awareness of its task even as intermediate work scrolls out of the window.</p><hr><h2 id="_4-recent-events-only" tabindex="-1">4. Recent Events Only <a class="header-anchor" href="#_4-recent-events-only" aria-label="Permalink to &quot;4. Recent Events Only&quot;">​</a></h2><p>OpenHands provides <code>RecentEventsCondenser</code> — even simpler:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> RecentEventsCondenser</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">RollingCondenser</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">    keep_events</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 50</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> condense</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> events</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">events</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> &lt;=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">keep_events</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#CDD6F4;"> events</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#EBA0AC;font-style:italic;"> events</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">-</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">keep_events</span><span style="color:#9399B2;">:]</span></span></code></pre></div><p>No anchoring. No bookends. Just the last N events.</p><p><strong>Best for:</strong> short sessions where the task fits within the window, repetitive tasks where earlier context is irrelevant, stateless tool-use patterns. <strong>Risk:</strong> losing initial instructions entirely. If the system prompt scrolls out, the agent drifts from its objective. Unsuitable for long-running autonomous sessions.</p><hr><h2 id="_5-amortized-forgetting" tabindex="-1">5. Amortized Forgetting <a class="header-anchor" href="#_5-amortized-forgetting" aria-label="Permalink to &quot;5. Amortized Forgetting&quot;">​</a></h2><p>OpenHands&#39; <code>AmortizedForgettingCondenser</code> probabilistically retains events with a bias toward recency — instead of a sharp cutoff, it gradually forgets.</p><ul><li>Each event gets a retention probability based on its age.</li><li>More recent events have higher probability of being kept.</li><li>On each compaction pass, events are independently sampled for retention.</li><li>Older events are gradually forgotten, not abruptly discarded.</li></ul><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> AmortizedForgettingCondenser</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">RollingCondenser</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">    max_events</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 100</span></span>
<span class="line"><span style="color:#CDD6F4;">    keep_first</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> int</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 5</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Each non-anchored event survives with probability</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # proportional to its recency rank.</span></span></code></pre></div><p><strong>Retention probability vs age:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Retention Prob.</span></span>
<span class="line"><span>1.0 |                                      ************</span></span>
<span class="line"><span>0.8 |                            **********</span></span>
<span class="line"><span>0.6 |                  **********</span></span>
<span class="line"><span>0.4 |        **********</span></span>
<span class="line"><span>0.2 |********</span></span>
<span class="line"><span>0.0 +-------------------------------------------------&gt;</span></span>
<span class="line"><span>    Oldest                                    Newest</span></span></code></pre></div><p><strong>Benefits:</strong> smoother degradation (no sharp cliff), probabilistic coverage (some old events survive), and repeated compaction as implicit importance filtering. <strong>Trade-off:</strong> non-deterministic — same conversation may produce different compacted histories on different runs, complicating debugging and reproducibility.</p><hr><h2 id="_6-observation-masking" tabindex="-1">6. Observation Masking <a class="header-anchor" href="#_6-observation-masking" aria-label="Permalink to &quot;6. Observation Masking&quot;">​</a></h2><p>A strategy operating on <strong>content</strong> rather than <strong>position</strong>: replace verbose observation payloads with compact structural placeholders.</p><p><strong>Before masking</strong> (~2,000 tokens):</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>[CmdOutputObservation]</span></span>
<span class="line"><span>$ cat src/auth/middleware.py</span></span>
<span class="line"><span>import jwt</span></span>
<span class="line"><span>from functools import wraps</span></span>
<span class="line"><span>from flask import request, jsonify</span></span>
<span class="line"><span>... (500 lines of Python code) ...</span></span>
<span class="line"><span>def verify_token(token):</span></span>
<span class="line"><span>    try:</span></span>
<span class="line"><span>        payload = jwt.decode(token, SECRET_KEY, algorithms=[&#39;HS256&#39;])</span></span>
<span class="line"><span>        return payload</span></span>
<span class="line"><span>    except jwt.ExpiredSignatureError:</span></span>
<span class="line"><span>        return None</span></span></code></pre></div><p><strong>After masking</strong> (~15 tokens):</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>[Previous observation: CmdOutputObservation (cat src/auth/middleware.py) - truncated]</span></span></code></pre></div><p><strong>Preserved:</strong> what command ran, output type, chronological position. <strong>Removed:</strong> actual file contents, command outputs, search results, stack traces.</p><p><strong>BrowserOutputCondenser</strong> is a specialized variant for web content — browser observations (full page DOM, screenshot descriptions) are among the largest payloads.</p><p>Zero LLM cost, significant token savings, and the conversation&#39;s structural skeleton remains intact. The agent knows &quot;I read that file&quot; and can re-read if needed.</p><hr><h2 id="_7-output-truncation-strategies" tabindex="-1">7. Output Truncation Strategies <a class="header-anchor" href="#_7-output-truncation-strategies" aria-label="Permalink to &quot;7. Output Truncation Strategies&quot;">​</a></h2><p>Rather than dropping entire messages, truncation <strong>trims individual outputs</strong> to a maximum size while preserving the most informative portions.</p><h3 id="per-item-truncation-codex" tabindex="-1">Per-Item Truncation (Codex) <a class="header-anchor" href="#per-item-truncation-codex" aria-label="Permalink to &quot;Per-Item Truncation (Codex)&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">const</span><span style="color:#FAB387;"> TRUNCATION_LIMIT</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> usize</span><span style="color:#94E2D5;"> =</span><span style="color:#FAB387;"> 10_000</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // ~10KB per output</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> truncate_output</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">output</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> limit</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> usize</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> &lt;=</span><span style="color:#CDD6F4;"> limit </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> prefix_size </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> limit </span><span style="color:#94E2D5;">*</span><span style="color:#FAB387;"> 2</span><span style="color:#94E2D5;"> /</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">   // ~67% from start</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> suffix_size </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> limit </span><span style="color:#94E2D5;">/</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">        // ~33% from end</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> truncated_chars </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -</span><span style="color:#CDD6F4;"> prefix_size </span><span style="color:#94E2D5;">-</span><span style="color:#CDD6F4;"> suffix_size</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> prefix </span><span style="color:#94E2D5;">=</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">..</span><span style="color:#CDD6F4;">prefix_size</span><span style="color:#9399B2;">];</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> suffix </span><span style="color:#94E2D5;">=</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -</span><span style="color:#CDD6F4;"> suffix_size</span><span style="color:#94E2D5;">..</span><span style="color:#9399B2;">];</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">prefix</span><span style="color:#9399B2;">}</span><span style="color:#F5C2E7;">\\n\\n</span><span style="color:#A6E3A1;">... </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">truncated_chars</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;"> chars truncated ...</span><span style="color:#F5C2E7;">\\n\\n</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">suffix</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p><strong>Why asymmetric (67/33)?</strong> Error messages cluster at the end (compiler errors, stack traces), while headers and structure appear at the start (signatures, imports). The elision marker tells the model content was removed.</p><h3 id="head-tail-mini-swe-agent" tabindex="-1">Head + Tail (mini-SWE-agent) <a class="header-anchor" href="#head-tail-mini-swe-agent" aria-label="Permalink to &quot;Head + Tail (mini-SWE-agent)&quot;">​</a></h3><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CDD6F4;">MAX_OUTPUT_CHARS </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 10_000</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> truncate</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">output</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#FAB387;font-style:italic;"> len</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> &lt;=</span><span style="color:#CDD6F4;"> MAX_OUTPUT_CHARS</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> output</span></span>
<span class="line"><span style="color:#CDD6F4;">    half </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> MAX_OUTPUT_CHARS </span><span style="color:#94E2D5;">//</span><span style="color:#FAB387;"> 2</span></span>
<span class="line"><span style="color:#CDD6F4;">    head </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> output</span><span style="color:#9399B2;">[:</span><span style="color:#EBA0AC;font-style:italic;">half</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">    tail </span><span style="color:#94E2D5;">=</span><span style="color:#EBA0AC;font-style:italic;"> output</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">-</span><span style="color:#EBA0AC;font-style:italic;">half</span><span style="color:#9399B2;">:]</span></span>
<span class="line"><span style="color:#CDD6F4;">    warning </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> (</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;</span><span style="color:#F5C2E7;">\\n\\n</span><span style="color:#A6E3A1;">[Output truncated. &quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;Use more targeted commands (e.g., grep -n, head, tail) &quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">        &quot;to get specific content.]</span><span style="color:#F5C2E7;">\\n\\n</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#9399B2;">    )</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> head </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> warning </span><span style="color:#94E2D5;">+</span><span style="color:#CDD6F4;"> tail</span></span></code></pre></div><p>The <strong>warning message</strong> teaches the model to use more precise commands next time, creating a feedback loop that reduces future truncation.</p><h3 id="search-result-limits-forgecode" tabindex="-1">Search Result Limits (ForgeCode) <a class="header-anchor" href="#search-result-limits-forgecode" aria-label="Permalink to &quot;Search Result Limits (ForgeCode)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>FORGE_MAX_SEARCH_RESULT_BYTES = 10240  # 10KB default</span></span></code></pre></div><p>Prevents a single <code>grep -r &quot;TODO&quot;</code> from flooding context with thousands of matches. Applied at the tool level before results enter the conversation, encouraging more specific search queries.</p><h3 id="global-truncation-pass-codex" tabindex="-1">Global Truncation Pass (Codex) <a class="header-anchor" href="#global-truncation-pass-codex" aria-label="Permalink to &quot;Global Truncation Pass (Codex)&quot;">​</a></h3><p>When total context exceeds the budget after per-item truncation, Codex iterates over ALL function call outputs and truncates each by increasing amounts until the total fits. A blunt emergency valve — rarely triggered if per-item limits are well-calibrated, but prevents catastrophic overflow.</p><hr><h2 id="_8-hybrid-approaches" tabindex="-1">8. Hybrid Approaches <a class="header-anchor" href="#_8-hybrid-approaches" aria-label="Permalink to &quot;8. Hybrid Approaches&quot;">​</a></h2><p>No production agent relies on a single strategy. The standard pattern is a <strong>pipeline of progressively more aggressive compaction</strong>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. Per-item truncation     (always on, ~0 cost)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>2. Observation masking     (cheap, structural preservation)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>3. Sliding window          (medium: loses context)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>4. LLM summarization       (expensive: tokens + latency)</span></span></code></pre></div><p><strong>OpenHands pipeline:</strong></p><ol><li><code>ObservationMasking</code> — replace old observation content with placeholders.</li><li><code>ConversationWindowCondenser</code> — drop middle events, preserve anchors.</li><li><code>LLMSummarizingCondenser</code> — LLM-generated summary as final fallback.</li></ol><p><strong>Codex pipeline:</strong></p><ol><li>Per-item truncation (10KB limit) on every tool output immediately.</li><li>Global truncation pass when total context approaches the limit.</li><li>Soft-cap rollover: new conversation with summary when context is exhausted.</li></ol><p>The principle: <strong>exhaust cheap strategies before spending on expensive ones</strong>.</p><hr><h2 id="_9-anchor-points-messages-that-should-never-be-dropped" tabindex="-1">9. Anchor Points: Messages That Should Never Be Dropped <a class="header-anchor" href="#_9-anchor-points-messages-that-should-never-be-dropped" aria-label="Permalink to &quot;9. Anchor Points: Messages That Should Never Be Dropped&quot;">​</a></h2><p>Certain messages carry disproportionate importance regardless of age:</p><ul><li><strong>System prompt:</strong> defines agent behavior, tools, constraints. Losing this causes the agent to &quot;forget what it is&quot; — a catastrophic failure mode.</li><li><strong>First user message:</strong> the original task description. Without it, the agent cannot verify whether current work aligns with the user&#39;s intent.</li><li><strong>Key decision points:</strong> when the user approved/rejected an approach. &quot;Don&#39;t use Redux, use Zustand&quot; must persist even 50 turns later.</li><li><strong>Error recovery records:</strong> when the agent changed approach after a dead end.</li><li><strong>File modification records:</strong> what was changed and why.</li></ul><p><strong>How to identify anchors:</strong></p><table tabindex="0"><thead><tr><th>Method</th><th>Approach</th><th>Trade-off</th></tr></thead><tbody><tr><td>Positional</td><td>First K messages always kept</td><td>Simple but inflexible</td></tr><tr><td>Role-based</td><td>System/user messages preserved, tool outputs trimmed</td><td>Reasonable default</td></tr><tr><td>Content-based</td><td>Messages with keywords (&quot;constraint&quot;, &quot;don&#39;t&quot;) flagged</td><td>Fragile heuristic</td></tr><tr><td>LLM-scored</td><td>LLM rates importance of each message</td><td>Expensive, adds latency</td></tr></tbody></table><p>Production default: <strong>positional anchoring</strong> (keep first K) combined with <strong>role-based priority</strong> (prefer user messages over tool outputs when compacting).</p><hr><h2 id="_10-comparison-table" tabindex="-1">10. Comparison Table <a class="header-anchor" href="#_10-comparison-table" aria-label="Permalink to &quot;10. Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strategy</th><th>Info Loss</th><th>LLM Cost</th><th>Latency</th><th>Preserves Anchors</th><th>Best For</th></tr></thead><tbody><tr><td>Simple window</td><td>High</td><td>None</td><td>~0ms</td><td>No</td><td>Ephemeral chat sessions</td></tr><tr><td>Anchor-preserving</td><td>Medium</td><td>None</td><td>~0ms</td><td>Yes</td><td>Long autonomous sessions</td></tr><tr><td>Recent events</td><td>High</td><td>None</td><td>~0ms</td><td>No</td><td>Short, focused tasks</td></tr><tr><td>Amortized forgetting</td><td>Medium</td><td>None</td><td>~0ms</td><td>Configurable</td><td>Balanced long sessions</td></tr><tr><td>Observation masking</td><td>Low-Medium</td><td>None</td><td>~0ms</td><td>Yes</td><td>Tool-heavy workflows</td></tr><tr><td>Per-item truncation</td><td>Low</td><td>None</td><td>~0ms</td><td>N/A</td><td>Large individual outputs</td></tr><tr><td>Head+tail split</td><td>Low</td><td>None</td><td>~0ms</td><td>N/A</td><td>Command/build outputs</td></tr><tr><td>Global truncation</td><td>Medium</td><td>None</td><td>~0ms</td><td>N/A</td><td>Emergency overflow</td></tr></tbody></table><p>Every strategy here has zero LLM cost — that is their defining characteristic. The differences lie in information loss and whether initial context survives.</p><hr><h2 id="_11-when-to-use-sliding-window-vs-summarization" tabindex="-1">11. When to Use Sliding Window vs Summarization <a class="header-anchor" href="#_11-when-to-use-sliding-window-vs-summarization" aria-label="Permalink to &quot;11. When to Use Sliding Window vs Summarization&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>                    Sliding Window          LLM Summarization</span></span>
<span class="line"><span>                    ──────────────          ─────────────────</span></span>
<span class="line"><span>Cost per use:       Free                    $0.001 - $0.05</span></span>
<span class="line"><span>Latency:            &lt; 1ms                   500ms - 5s</span></span>
<span class="line"><span>Info preservation:  Low (positional)        High (semantic)</span></span>
<span class="line"><span>Deterministic:      Yes*                    No</span></span>
<span class="line"><span>Implementation:     Trivial                 Moderate</span></span>
<span class="line"><span>Failure modes:      Loses key context       Bad summary, hallucination</span></span></code></pre></div><p>*Amortized forgetting is non-deterministic.</p><p><strong>Use sliding window when:</strong></p><ul><li>Sessions are short (&lt; 30 turns) and recent context suffices.</li><li>Cost sensitivity is high and every API call matters.</li><li>Latency is critical (real-time interactive use).</li><li>The task is repetitive and earlier context is genuinely irrelevant.</li></ul><p><strong>Use LLM summarization when:</strong></p><ul><li>Sessions are long (50+ turns) with complex state evolution.</li><li>Multiple interrelated decisions need to be preserved.</li><li>The agent needs to recall <em>why</em> it made earlier choices.</li></ul><p><strong>Use both (hybrid) when:</strong></p><ul><li>Building production agents handling variable-length sessions.</li><li>Cheap strategies as first defense, summarization as fallback.</li><li>Pipeline should degrade gracefully: fast/cheap for simple sessions, slower/thorough for complex ones.</li></ul><p>The trend in production agents is clearly toward <strong>hybrid pipelines</strong> where sliding window and truncation handle the common case while LLM summarization activates only when cheap strategies cause unacceptable information loss.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Sliding window and truncation strategies are the <strong>workhorses</strong> of context management — not because they&#39;re sophisticated, but because they&#39;re fast, free, and reliable. The art lies in composing a pipeline that applies the right strategy at each stage of context pressure. The key design decisions are:</p><ol><li><strong>Where to anchor</strong>: which messages must survive all compaction.</li><li><strong>How to split</strong>: asymmetric (67/33) vs symmetric (50/50) for truncation.</li><li><strong>When to escalate</strong>: thresholds for moving from cheap to expensive strategies.</li><li><strong>What to preserve</strong>: structure (masking) vs content (summarization).</li></ol>`,95)])])}const h=n(o,[["render",l]]);export{u as __pageData,h as default};
